import { useState, useEffect, useRef } from "react";

function ConstellationBG() {
  const ref = useRef(null);
  const mouse = useRef({ x: -999, y: -999 });
  useEffect(() => {
    const c = ref.current; if (!c) return;
    const ctx = c.getContext("2d");
    let W, H, pts = [], raf;
    const resize = () => { W = c.width = window.innerWidth; H = c.height = window.innerHeight; };
    resize();
    for (let i = 0; i < 55; i++) pts.push({ x: Math.random()*2000, y: Math.random()*1200, r: Math.random()*1.6+0.4, vx: (Math.random()-0.5)*0.25, vy: (Math.random()-0.5)*0.18, base_o: Math.random()*0.45+0.12, hue: Math.random()>0.55?[255,214,0]:Math.random()>0.4?[3,205,0]:[0,180,212] });
    const onMouse = e => { mouse.current = { x: e.clientX, y: e.clientY }; };
    window.addEventListener("mousemove", onMouse);
    const draw = () => {
      ctx.clearRect(0,0,W,H); const mx=mouse.current.x, my=mouse.current.y;
      pts.forEach(p => {
        p.x+=p.vx; p.y+=p.vy;
        if(p.x<-20)p.x=W+20; if(p.x>W+20)p.x=-20; if(p.y<-20)p.y=H+20; if(p.y>H+20)p.y=-20;
        const ddx=p.x-mx,ddy=p.y-my,md=Math.sqrt(ddx*ddx+ddy*ddy);
        if(md<150&&md>0){const f=(150-md)/150*0.8;p.x+=(ddx/md)*f;p.y+=(ddy/md)*f;}
        ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,Math.PI*2);ctx.fillStyle=`rgba(${p.hue},${p.base_o})`;ctx.fill();
        const g=ctx.createRadialGradient(p.x,p.y,0,p.x,p.y,p.r*6);
        g.addColorStop(0,`rgba(${p.hue},${p.base_o*0.12})`);g.addColorStop(1,`rgba(${p.hue},0)`);
        ctx.beginPath();ctx.arc(p.x,p.y,p.r*6,0,Math.PI*2);ctx.fillStyle=g;ctx.fill();
      });
      for(let i=0;i<pts.length;i++)for(let j=i+1;j<pts.length;j++){const dx=pts[i].x-pts[j].x,dy=pts[i].y-pts[j].y,d=Math.sqrt(dx*dx+dy*dy);if(d<140){ctx.beginPath();ctx.moveTo(pts[i].x,pts[i].y);ctx.lineTo(pts[j].x,pts[j].y);ctx.strokeStyle=`rgba(255,214,0,${0.035*(1-d/140)})`;ctx.lineWidth=0.6;ctx.stroke();}}
      raf=requestAnimationFrame(draw);
    };
    draw(); window.addEventListener("resize",resize);
    return()=>{cancelAnimationFrame(raf);window.removeEventListener("resize",resize);window.removeEventListener("mousemove",onMouse);};
  },[]);
  return <canvas ref={ref} style={{position:"fixed",inset:0,pointerEvents:"none",zIndex:1,opacity:.85}}/>;
}

function Spotlight(){const ref=useRef(null);useEffect(()=>{let mx=-500,my=-500,cx=-500,cy=-500;const move=e=>{mx=e.clientX;my=e.clientY};const tick=()=>{cx+=(mx-cx)*0.05;cy+=(my-cy)*0.05;if(ref.current)ref.current.style.background=`radial-gradient(700px circle at ${cx}px ${cy}px,rgba(255,214,0,.025),transparent 55%)`;requestAnimationFrame(tick)};window.addEventListener("mousemove",move);tick();return()=>window.removeEventListener("mousemove",move)},[]);return <div ref={ref} style={{position:"fixed",inset:0,pointerEvents:"none",zIndex:2}}/>}

function Cursor(){const dot=useRef(null),ring=useRef(null);useEffect(()=>{let mx=0,my=0,rx=0,ry=0;const move=e=>{mx=e.clientX;my=e.clientY;if(dot.current){dot.current.style.left=mx+"px";dot.current.style.top=my+"px"}};const tick=()=>{rx+=(mx-rx)*0.1;ry+=(my-ry)*0.1;if(ring.current){ring.current.style.left=rx+"px";ring.current.style.top=ry+"px"}requestAnimationFrame(tick)};window.addEventListener("mousemove",move);tick();const enter=()=>{if(ring.current){ring.current.style.transform="translate(-50%,-50%) scale(2)";ring.current.style.borderColor="rgba(255,214,0,.6)"}};const leave=()=>{if(ring.current){ring.current.style.transform="translate(-50%,-50%) scale(1)";ring.current.style.borderColor="rgba(255,214,0,.3)"}};const attach=()=>document.querySelectorAll("a,button,.hov").forEach(el=>{el.addEventListener("mouseenter",enter);el.addEventListener("mouseleave",leave)});attach();const mo=new MutationObserver(attach);mo.observe(document.body,{childList:true,subtree:true});return()=>{window.removeEventListener("mousemove",move);mo.disconnect()}},[]);return(<><div ref={dot} style={{position:"fixed",width:5,height:5,background:"#FFD600",borderRadius:"50%",pointerEvents:"none",zIndex:10001,transform:"translate(-50%,-50%)",boxShadow:"0 0 8px rgba(255,214,0,.4)"}}/><div ref={ring} style={{position:"fixed",width:32,height:32,border:"1.5px solid rgba(255,214,0,.3)",borderRadius:"50%",pointerEvents:"none",zIndex:10000,transform:"translate(-50%,-50%) scale(1)",transition:"transform .15s ease,border-color .15s"}}/></>)}

function useTilt(n=8){const ref=useRef(null);useEffect(()=>{const el=ref.current;if(!el)return;const m=e=>{const r=el.getBoundingClientRect();const x=(e.clientX-r.left)/r.width-0.5;const y=(e.clientY-r.top)/r.height-0.5;el.style.transform=`perspective(800px) rotateY(${x*n}deg) rotateX(${-y*n}deg) translateY(-4px)`;el.style.transition="transform 0.1s ease"};const l=()=>{el.style.transform="perspective(800px) rotateY(0) rotateX(0) translateY(0)";el.style.transition="transform 0.5s ease"};el.addEventListener("mousemove",m);el.addEventListener("mouseleave",l);return()=>{el.removeEventListener("mousemove",m);el.removeEventListener("mouseleave",l)}},[n]);return ref}

function Counter({value,color}){const ref=useRef(null);const[d,setD]=useState("0");useEffect(()=>{const io=new IntersectionObserver(e=>{if(e[0].isIntersecting){const num=parseInt(value)||0;if(!num){setD(value);io.disconnect();return}const t0=performance.now();const tick=now=>{const p=Math.min((now-t0)/1200,1);setD(Math.round((1-Math.pow(1-p,3))*num).toString());if(p<1)requestAnimationFrame(tick)};requestAnimationFrame(tick);io.disconnect()}},{threshold:0.3});if(ref.current)io.observe(ref.current);return()=>io.disconnect()},[value]);return <span ref={ref} className="counter" style={{color}}>{d}</span>}

function useReveal(){useEffect(()=>{const io=new IntersectionObserver(e=>e.forEach(e=>{if(e.isIntersecting){e.target.classList.add("vi");io.unobserve(e.target)}}),{threshold:0.06,rootMargin:"0px 0px -30px 0px"});document.querySelectorAll(".rv").forEach(el=>io.observe(el));return()=>io.disconnect()},[])}

function MagBtn({href,children,className="btn-p",style}){const ref=useRef(null);const m=e=>{const r=ref.current.getBoundingClientRect();ref.current.style.transform=`translate(${(e.clientX-r.left-r.width/2)*0.15}px,${(e.clientY-r.top-r.height/2)*0.15}px)`};const l=()=>{ref.current.style.transform="translate(0,0)"};const click=e=>{if(href&&href.startsWith("#")){e.preventDefault();const el=document.querySelector(href);if(el)el.scrollIntoView({behavior:"smooth",block:"start"})}};return <a ref={ref} href={href||"#"} className={`${className} hov mag`} onMouseMove={m} onMouseLeave={l} onClick={click} style={style} target={href&&href.startsWith("http")?"_blank":undefined} rel={href&&href.startsWith("http")?"noopener noreferrer":undefined}>{children}</a>}

