function Workflow(){const s=[{n:"01",t:"Market Opens",b:"Pivot-based levels plotted automatically on your chart.",c:"#FFD600"},{n:"02",t:"Flow Tracker Reads",b:"Three-layer bias produces an Overall verdict in real time.",c:"#E8A317"},{n:"03",t:"Bias Gate Activates",b:"Favourable? Levels appear. If not, everything hides.",c:"#03CD00"},{n:"04",t:"Execute the Plan",b:"Enter at Entry, stop at SL, scale out at TP1–TP5.",c:"#E07B00"},{n:"05",t:"Alerts Do the Rest",b:"Smart alerts notify you when price hits any key level.",c:"#00B4D8"}];return(<Sec id="how" ey="THE WORKFLOW"><h2 className="sec-h2 rv"><span className="hw">From market open</span><br/><span className="hd">to executed trade.</span></h2><div className="wf-g rv">{s.map((s,i)=><div key={i} className="wf-s hov" style={{"--wc":s.c}}><div className="wf-top" style={{background:s.c,boxShadow:`0 2px 16px ${s.c}44`}}/><span className="wf-n" style={{color:s.c}}>{s.n}</span><div className="wf-t">{s.t}</div><p className="wf-b">{s.b}</p></div>)}</div></Sec>)}

function TD({n,name,sub,body,accent,panel,feats}){return(<Sec><div className="td-lay"><div className="td-l rv"><span className="tool-badge" style={{borderColor:accent,color:accent}}>Tool {n}</span><h3 className="td-name">{name}</h3><span className="td-sub" style={{color:accent}}>{sub}</span><p className="td-body">{body}</p>{panel}</div><div className="td-r">{feats.map((f,i)=><div key={i} className="td-feat rv"><span className="td-dot" style={{background:f.d,boxShadow:`0 0 10px ${f.d}55`}}/><div><div className="td-ft">{f.t}</div><p className="td-fb">{f.b}</p></div></div>)}</div></div></Sec>)}

function FlowTracker(){return <TD n="01" name={<>Sooty Flow<br/>Tracker</>} sub="The Intelligence Layer" accent="#FFD600" body="Reads the market across three independent layers and produces a weighted consensus verdict." panel={<div className="flow-p">{[["Pressure","Buy","fpb"],["Trend","Buy","fpb"],["Overall","Strong Buy","fps"]].map(([l,v,c],i)=><div key={i} className="fp-r"><span className="fp-l">{l}</span><span className={`fp-v ${c}`}>{v}</span></div>)}</div>} feats={[{d:"#FFD600",t:"Three-Layer Bias Voting",b:"Pressure + Trend combine into one weighted Overall verdict."},{d:"#FF3333",t:"DO NOT ENTER Protection",b:"No alignment? System outputs DO NOT ENTER."},{d:"#03CD00",t:"Strong Buy / Strong Sell Signals",b:"Only fires when all layers agree — highest conviction."},{d:"#00B4D8",t:"Three Visual Indicator Lines",b:"Yellow, Blue, Orange lines read market structure at every speed."}]}/>}

