function Benefits(){return(<Sec id="benefits" ey="KEY BENEFITS" center><h2 className="sec-h2 rv"><span className="hw">What SootyEdge</span><br/><span className="hd">gives you.</span></h2><div className="ben-g">{[{v:"1",l:"Clear Signal",b:"One table. One verdict. No conflicting indicators.",c:"#FFD600"},{v:"7",l:"Levels Drawn",b:"Entry, SL, TP1–5 plotted every session automatically.",c:"#00B4D8"},{v:"0",l:"Guesswork",b:"The system tells you where to enter, stop, and exit.",c:"#03CD00"},{v:"∞",l:"Markets",b:"Stocks, forex, crypto, futures. Any TradingView market.",c:"#FFD600"},{v:"24",l:"Hour Alerts",b:"Webhook alerts monitor the market around the clock.",c:"#00B4D8"},{v:"2",l:"Tools, 1 Edge",b:"Intelligence + execution in one seamless framework.",c:"#03CD00"}].map((b,i)=><div key={i} className="ben-c rv hov"><Counter value={b.v} color={b.c}/><div className="ben-l">{b.l}</div><p className="ben-b">{b.b}</p></div>)}</div></Sec>)}

